+            Self {
+                connectors,
+                list_calls,
+            }
+        }
+
+        fn find(&self, id: &ConnectorId) -> Option<ConnectorSummary> {
+            self.connectors.iter().find(|c| &c.id == id).cloned()
+        }
+    }
+
+    #[async_trait::async_trait]
+    impl ConnectorRegistry for CountingRegistry {
